    });

    // 3. Create reactive calculation using create (squared value)
    auto squaredCalc = reaction::create<reaction::Calc<int>>([expression]() {
        int val = expression.get();
        return val * val;
    });

    // 4. Get initial expression value
    int initialExpressionValue = expression.get();

    // 5. Update reactive variable
    reactiveVar.set(reactiveVar.get() + increment);

    // 6. Get updated expression value
    int updatedExpressionValue = expression.get();

    // 7. Get squared value after update
    int squaredValueAfterUpdate = squaredCalc.get();

    // 8. Return expression and calculation results
    return CreateFactoryResult{
        initialExpressionValue,
        updatedExpressionValue,
        squaredValueAfterUpdate
    };
}

}  // namespace test_reaction
