    auto varA = var(a);
    auto varB = var(b);
    // Build negated sum directly as a prvalue expression so expr() sees a valid OpExprauto
    auto negatedReact = expr(make_unary_op<NegOp>(make_binary_op<AddOp>(varA, varB)));
