struct GenericCacheStatsSnapshot {
    std::size_t entriesBefore;
    std::size_t entriesAfterInsert;
    std::size_t entriesAfterInvalidate;
    std::size_t hitCount;
    std::size_t missCount;
    double hitRatio;
    bool firstLookupWasMiss;
    bool secondLookupWasHit;
};

GenericCacheStatsSnapshot test_generic_cache_base() {
    // 1. Define IntCache class inheriting from CacheBase
    class IntCache : public reaction::CacheBase<int, int> {
    public:
        // 2. Expose CacheBase methods using using declarations
        using reaction::CacheBase<int, int>::lookup;
        using reaction::CacheBase<int, int>::insert;
        using reaction::CacheBase<int, int>::invalidateAll;
        using reaction::CacheBase<int, int>::cleanup;
        using reaction::CacheBase<int, int>::getStats;
        using reaction::CacheBase<int, int>::getCacheStats;
    };

    // 3. Create IntCache instance
    IntCache cache;

    GenericCacheStatsSnapshot snapshot{};

    // 4. Get initial cache statistics
    auto initialStats = cache.getStats();
    snapshot.entriesBefore = initialStats.entryCount;

    // 5. Perform initial lookup
    int key = 42;
    auto firstLookup = cache.lookup(key);
    snapshot.firstLookupWasMiss = (firstLookup == nullptr);

    // 6. Insert value into cache
    int value = 100;
    cache.insert(key, value);

    // 7. Perform second lookup
    auto secondLookup = cache.lookup(key);
    snapshot.secondLookupWasHit = (secondLookup != nullptr);

    // 8. Get cache statistics after insertion
    auto statsAfterInsert = cache.getStats();
    snapshot.entriesAfterInsert = statsAfterInsert.entryCount;

    // 9. Invalidate all cache entries
    cache.invalidateAll();

    // 10. Trigger cleanup
    cache.cleanup();

    // 11. Get cache statistics after invalidation
    auto statsAfterInvalidate = cache.getStats();
    snapshot.entriesAfterInvalidate = statsAfterInvalidate.entryCount;

    // 12. Return generic cache stats snapshot
    snapshot.hitCount = statsAfterInvalidate.hitCount;
    snapshot.missCount = statsAfterInvalidate.missCount;

    auto totalAccesses = snapshot.hitCount + snapshot.missCount;
    snapshot.hitRatio = totalAccesses > 0 ? 
        static_cast<double>(snapshot.hitCount) / totalAccesses : 0.0;

    return snapshot;
}

}  // namespace test_reaction
